#include <iostream>
#include <string>

class Item {
public:
    Item(std::string name, int qty, int price)
        : m_name{name}, m_qty{qty}, m_price{price} {}

    std::string name() const { return m_name; }
    int quantity() const { return m_qty; }
    int unitPrice() const { return m_price; }
    int total() const { return m_qty * m_price; }

