#include <iostream>

class Temperature {
public:
    explicit Temperature(int c) : m_celsius{c} {}
    int celsius() const { return m_celsius; }
    int toFahrenheit() const { return m_celsius * 9 / 5 + 32; }
private:
    int m_celsius;
};

int main() {
    int n;
    std::cin >> n;
    for (int i = 0; i < n; ++i) {
        int c;
        std::cin >> c;
        Temperature t{c};
        std::cout << t.celsius() << "C = " << t.toFahrenheit() << "F\n";
    }
}
